using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF9: Discriminator property renamed to "$type" — preserve old name for existing documents
        // EF9: id no longer contains discriminator — preserve "Blog|1" format for existing documents
        modelBuilder.Entity<Blog>(b =>
        {
            b.HasDiscriminator<string>("Discriminator");
            b.HasRootDiscriminatorInJsonId(true);
        });
        // EF9: HasIndex now throws for Cosmos entities — removed (manage via Azure indexing policy)
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

